import ProtonJSX from "./ProtonJSX"
import { VNodeHandle, vnodePool } from "./VNodePool"

export type { VNodeHandle } from "./VNodePool"
export { ChildrenType } from "./ProtonJSX"

const FragmentSymbol = ProtonJSX.FragmentSymbol
export { FragmentSymbol }

/**
 * Creates a flat vnode backed by the global VNodePool.
 *
 * The returned `VNodeHandle` is a number (index into the pool).
 * Children that are themselves valid `VNodeHandle` values are
 * automatically linked into a firstChild / nextSibling chain
 * for efficient tree iteration.
 */
export function flatJSX(type: any, rawProps: Record<string, any> | null): VNodeHandle {
  const idx = vnodePool.allocate(type, rawProps)
  if (rawProps == null) return idx

  linkChildren(idx, rawProps.children)
  return idx
}

function linkChildren(parent: VNodeHandle, children: unknown): void {
  if (children == null) return

  if (typeof children === "number" && vnodePool.isValid(children)) {
    vnodePool.setParent(children, parent)
    vnodePool.setFirstChild(parent, children)
    return
  }

  if (Array.isArray(children)) {
    let first: VNodeHandle = -1
    let prev: VNodeHandle = -1

    for (let ci = 0; ci < children.length; ci++) {
      const child = children[ci]
      if (typeof child === "number" && vnodePool.isValid(child)) {
        vnodePool.setParent(child, parent)
        if (prev === -1) {
          first = child
        } else {
          vnodePool.setNextSibling(prev, child)
        }
        prev = child
      }
    }

    if (first !== -1) {
      vnodePool.setFirstChild(parent, first)
    }
  }
}

export default flatJSX
