import { ChildrenType } from "./ProtonJSX"

export type VNodeHandle = number

const INIT = 64

/**
 * Dense, TypedArray-backed storage for a flat vnode tree.
 *
 * Each vnode is an index into parallel arrays:
 *   _types / _props   – reference storage (any[])
 *   _meta             – childrenType + flags (Uint8Array)
 *   _parent           – parent index, -1 = root (Int32Array)
 *   _firstChild       – first child index, -1 = none (Int32Array)
 *   _nextSibling      – next sibling index, -1 = none (Int32Array)
 *
 * The pool grows monotonically.  No free-list — slots are never reused,
 * keeping the generation-less index scheme simple and safe.
 */
export class VNodePool {
  _size = 0
  _cap = INIT

  _types: any[] = new Array(INIT)
  _props: (Record<string, any> | null)[] = new Array(INIT)

  _meta = new Uint8Array(INIT)
  _parent = new Int32Array(INIT)
  _firstChild = new Int32Array(INIT)
  _nextSibling = new Int32Array(INIT)

  allocate(type: any, rawProps: Record<string, any> | null): VNodeHandle {
    const i = this._size
    if (i >= this._cap) this._grow()

    this._types[i] = type
    this._props[i] = rawProps ?? null

    const children = rawProps?.children
    let ct: ChildrenType

    if (children == null) {
      ct = ChildrenType.None
    } else if (typeof children !== "object" || children === null) {
      ct = typeof children === "function" ? ChildrenType.VNode : ChildrenType.Primitive
      if (typeof children === "number" && this.isValid(children)) ct = ChildrenType.VNode
    } else if ((children as any).type != null && !Array.isArray(children)) {
      ct = ChildrenType.VNode
    } else if (Array.isArray(children)) {
      ct = ChildrenType.ArrayStatic
      for (const child of children) {
        if (child != null && typeof child === "object" && typeof (child as any).subscribe === "function") {
          ct = ChildrenType.ArrayReactive
          break
        }
      }
    } else if (Symbol.iterator in children) {
      ct = ChildrenType.ArrayStatic
    } else if (typeof (children as any).subscribe === "function") {
      ct = ChildrenType.ObservableText
    } else {
      ct = ChildrenType.VNode
    }
    this._meta[i] = ct

    this._parent[i] = -1
    this._firstChild[i] = -1
    this._nextSibling[i] = -1

    this._size++
    return i
  }

  private _grow() {
    const cap = this._cap * 2

    const newMeta = new Uint8Array(cap)
    newMeta.set(this._meta)
    this._meta = newMeta

    const newParent = new Int32Array(cap)
    newParent.set(this._parent)
    this._parent = newParent

    const newFirstChild = new Int32Array(cap)
    newFirstChild.set(this._firstChild)
    this._firstChild = newFirstChild

    const newNextSibling = new Int32Array(cap)
    newNextSibling.set(this._nextSibling)
    this._nextSibling = newNextSibling

    this._types.length = cap
    this._props.length = cap
    this._cap = cap
  }

  // -- accessors (inlined for perf) --

  getType(i: VNodeHandle) { return this._types[i] }

  getProps(i: VNodeHandle) { return this._props[i] }

  getChildrenType(i: VNodeHandle): ChildrenType { return this._meta[i] as ChildrenType }

  getFirstChild(i: VNodeHandle) { return this._firstChild[i] }

  getNextSibling(i: VNodeHandle) { return this._nextSibling[i] }

  getParent(i: VNodeHandle) { return this._parent[i] }

  setParent(i: VNodeHandle, p: VNodeHandle) { this._parent[i] = p }

  setFirstChild(i: VNodeHandle, c: VNodeHandle) { this._firstChild[i] = c }

  setNextSibling(i: VNodeHandle, n: VNodeHandle) { this._nextSibling[i] = n }

  /** Returns true when `i` is a valid, live VNode handle. */
  isValid(i: VNodeHandle): boolean {
    return Number.isInteger(i) && i >= 0 && i < this._size
  }
}

export const vnodePool = new VNodePool()
